fixed_code:
// Define an enum with two variants
enum MyEnum {
    Variant1,
    Variant2,
}

fn main() {
    match MyEnum::Variant1 {
        MyEnum::Variant1 => println!("Variant 1"),
        MyEnum::Variant2 => println!("Variant 2"),
    }
}
